package org.apache.commons.csv;
import static org.apache.commons.csv.Constants.BACKSLASH;
import static org.apache.commons.csv.Constants.COMMA;
import static org.apache.commons.csv.Constants.CR;
import static org.apache.commons.csv.Constants.CRLF;
import static org.apache.commons.csv.Constants.DOUBLE_QUOTE_CHAR;
import static org.apache.commons.csv.Constants.LF;
import static org.apache.commons.csv.Constants.TAB;
import java.io.Reader;
import java.io.Serializable;
import java.util.Arrays;
import java.util.HashSet;
import java.util.Set;

import static org.junit.jupiter.api.Assertions.*;
import static org.mockito.Mockito.*;

import java.io.IOException;
import java.io.StringWriter;

import org.junit.jupiter.api.BeforeEach;
import org.junit.jupiter.api.Test;

import java.lang.reflect.InvocationHandler;
import java.lang.reflect.Method;
import java.lang.reflect.Proxy;

class CSVFormatTest {

    private CSVFormat csvFormat;

    @BeforeEach
    void setUp() {
        csvFormat = CSVFormat.DEFAULT;
    }

    @Test
    void testFormat_withNormalValues() throws IOException {
        String result = csvFormat.format("a", "b", "c");
        assertEquals("a,b,c", result);
    }

    @Test
    void testFormat_withEmptyValues() throws IOException {
        String result = csvFormat.format();
        assertEquals("", result);
    }

    @Test
    void testFormat_withNullValues() throws IOException {
        String result = csvFormat.format((Object) null);
        assertEquals("", result);
    }

    @Test
    void testFormat_trimsResult() throws IOException {
        String result = csvFormat.format(" a ", " b ");
        // The CSVPrinter adds quotes if necessary, but our format trims output
        assertEquals("\" a \",\" b \"", result);
    }

    @Test
    void testFormat_throwsIllegalStateExceptionOnIOException() {
        // Create a proxy CSVPrinter that throws IOException on printRecord
        CSVPrinter proxyPrinter = (CSVPrinter) Proxy.newProxyInstance(
                CSVPrinter.class.getClassLoader(),
                new Class<?>[]{CSVPrinter.class},
                new InvocationHandler() {
                    @Override
                    public Object invoke(Object proxy, Method method, Object[] args) throws Throwable {
                        if ("printRecord".equals(method.getName())) {
                            throw new IOException("forced IOException");
                        }
                        if (method.getReturnType().isPrimitive()) {
                            if (method.getReturnType() == boolean.class) return false;
                            if (method.getReturnType() == int.class) return 0;
                            if (method.getReturnType() == long.class) return 0L;
                            if (method.getReturnType() == float.class) return 0f;
                            if (method.getReturnType() == double.class) return 0d;
                            if (method.getReturnType() == byte.class) return (byte) 0;
                            if (method.getReturnType() == char.class) return (char) 0;
                            if (method.getReturnType() == short.class) return (short) 0;
                        }
                        return null;
                    }
                });

        // Create a wrapper instance that overrides format to use the proxy CSVPrinter
        CSVFormat csvFormatProxy = new CSVFormatWrapper(csvFormat, proxyPrinter);

        IllegalStateException thrown = assertThrows(IllegalStateException.class, () -> {
            csvFormatProxy.format("x");
        });
        assertTrue(thrown.getCause() instanceof IOException);
        assertEquals("forced IOException", thrown.getCause().getMessage());
    }

    // Wrapper class to override format method to use proxy CSVPrinter
    private static class CSVFormatWrapper {
        private final CSVFormat delegate;
        private final CSVPrinter proxyPrinter;

        CSVFormatWrapper(CSVFormat delegate, CSVPrinter proxyPrinter) {
            this.delegate = delegate;
            this.proxyPrinter = proxyPrinter;
        }

        public String format(final Object... values) {
            try {
                proxyPrinter.printRecord(values);
                // Since proxyPrinter doesn't write to any Appendable, return empty string
                return "";
            } catch (IOException e) {
                throw new IllegalStateException(e);
            }
        }

        // Delegate all public methods to the original CSVFormat instance

        public Character getCommentMarker() {
            return delegate.getCommentMarker();
        }

        public char getDelimiter() {
            return delegate.getDelimiter();
        }

        public Character getEscapeCharacter() {
            return delegate.getEscapeCharacter();
        }

        public String[] getHeader() {
            return delegate.getHeader();
        }

        public boolean getAllowMissingColumnNames() {
            return delegate.getAllowMissingColumnNames();
        }

        public boolean getIgnoreEmptyLines() {
            return delegate.getIgnoreEmptyLines();
        }

        public boolean getIgnoreSurroundingSpaces() {
            return delegate.getIgnoreSurroundingSpaces();
        }

        public String getNullString() {
            return delegate.getNullString();
        }

        public Character getQuoteCharacter() {
            return delegate.getQuoteCharacter();
        }

        public QuoteMode getQuoteMode() {
            return delegate.getQuoteMode();
        }

        public String getRecordSeparator() {
            return delegate.getRecordSeparator();
        }

        public boolean getSkipHeaderRecord() {
            return delegate.getSkipHeaderRecord();
        }

        public boolean isCommentMarkerSet() {
            return delegate.isCommentMarkerSet();
        }

        public boolean isEscapeCharacterSet() {
            return delegate.isEscapeCharacterSet();
        }

        public boolean isNullStringSet() {
            return delegate.isNullStringSet();
        }

        public CSVFormat withCommentMarker(final char commentMarker) {
            return delegate.withCommentMarker(commentMarker);
        }

        public CSVFormat withCommentMarker(final Character commentMarker) {
            return delegate.withCommentMarker(commentMarker);
        }

        public CSVFormat withDelimiter(final char delimiter) {
            return delegate.withDelimiter(delimiter);
        }

        public CSVFormat withEscape(final char escape) {
            return delegate.withEscape(escape);
        }

        public CSVFormat withEscape(final Character escape) {
            return delegate.withEscape(escape);
        }

        public CSVFormat withHeader(final String... header) {
            return delegate.withHeader(header);
        }

        public CSVFormat withAllowMissingColumnNames(final boolean allowMissingColumnNames) {
            return delegate.withAllowMissingColumnNames(allowMissingColumnNames);
        }

        public CSVFormat withIgnoreEmptyLines(final boolean ignoreEmptyLines) {
            return delegate.withIgnoreEmptyLines(ignoreEmptyLines);
        }

        public CSVFormat withIgnoreSurroundingSpaces(final boolean ignoreSurroundingSpaces) {
            return delegate.withIgnoreSurroundingSpaces(ignoreSurroundingSpaces);
        }

        public CSVFormat withNullString(final String nullString) {
            return delegate.withNullString(nullString);
        }

        public CSVFormat withQuote(final char quoteChar) {
            return delegate.withQuote(quoteChar);
        }

        public CSVFormat withQuote(final Character quoteChar) {
            return delegate.withQuote(quoteChar);
        }

        public CSVFormat withQuoteMode(final QuoteMode quoteModePolicy) {
            return delegate.withQuoteMode(quoteModePolicy);
        }

        public CSVFormat withRecordSeparator(final char recordSeparator) {
            return delegate.withRecordSeparator(recordSeparator);
        }

        public CSVFormat withRecordSeparator(final String recordSeparator) {
            return delegate.withRecordSeparator(recordSeparator);
        }

        public CSVFormat withSkipHeaderRecord(final boolean skipHeaderRecord) {
            return delegate.withSkipHeaderRecord(skipHeaderRecord);
        }

        public CSVPrinter print(final Appendable out) throws IOException {
            return delegate.print(out);
        }

        public CSVParser parse(final java.io.Reader in) throws IOException {
            return delegate.parse(in);
        }

        @Override
        public boolean equals(final Object obj) {
            return delegate.equals(obj);
        }

        @Override
        public int hashCode() {
            return delegate.hashCode();
        }

        @Override
        public String toString() {
            return delegate.toString();
        }
    }
}
